import pandas as pd

try:
    # Try to read the CSV file directly
    df = pd.read_csv('data.csv')
    print("Data loaded successfully. Columns:", df.columns.tolist())

    # Look for embarkation column
    embark_col = None
    possible_names = ['Embarked', 'Embarkation', 'embarked', 'embarkation', 'Port of Embarkation']
    for col in df.columns:
        if col in possible_names:
            embark_col = col
            break

    # If not found, try case-insensitive search
    if embark_col is None:
        for col in df.columns:
            if 'embark' in col.lower():
                embark_col = col
                break

    if embark_col is None:
        print("ERROR: Could not find embarkation column. Available columns:", df.columns.tolist())
    else:
        print(f"Using column '{embark_col}' for embarkation town.")

        # Count occurrences of each embarkation town
        embark_counts = df[embark_col].value_counts()

        # Get the most common town and its count
        most_common_town = embark_counts.index[0]
        count = embark_counts.iloc[0]

        print(f"Most common embarkation town: {most_common_town} with {count} passengers.")
        print('ANSWER:', most_common_town, count)

except FileNotFoundError:
    print("ERROR: data.csv not found in current directory.")
except Exception as e:
    print(f"ERROR: {type(e).__name__}: {e}")
